from smolagents import Agent, tool
from vex import verify

@tool
def write_code(task: str) -> str:
    """Generate Python code for the given task."""
    return agent_model.generate(f"Write Python code for: {task}")

@tool
def execute_sandbox(code: str) -> dict:
    """Execute code in sandbox and return results."""
    result = sandbox.run(code)
    return {"output": result.stdout, "error": result.stderr, "passed": result.tests_passed}

agent = Agent(tools=[write_code, execute_sandbox])

# Wrapped with Vex
result = verify(agent.run("Write a function to sort a list"))

TESTS = """
def test_fibonacci():
    assert fibonacci(0) == 0
    assert fibonacci(1) == 1
    assert fibonacci(5) == 5
"""

@tool
def generate_with_tests(task: str, tests: str) -> str:
